SELECT bs."in.geometry_building_type_recs" AS geometry_building_type_recs, date_trunc('month', date_add('second', -900, resstock_2024_amy2018_release_2_by_state_vu.timestamp)) AS timestamp, count(distinct(bs.bldg_id)) AS sample_count, (count(distinct(bs.bldg_id)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(1) / CAST(count(distinct(bs.bldg_id)) AS DECIMAL) AS rows_per_sample, sum(resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption", sum(resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = resstock_2024_amy2018_release_2_by_state_vu.bldg_id AND bs.upgrade = 0 AND resstock_2024_amy2018_release_2_by_state_vu.upgrade = 1 AND resstock_2024_amy2018_release_2_by_state_vu.state = 'CO' AND resstock_2024_amy2018_release_2_by_state_vu.bldg_id IN (SELECT bs.bldg_id FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.upgrade IN (1) AND bs.applicability = true GROUP BY bs.bldg_id HAVING count(distinct(bs.upgrade)) = 1) GROUP BY 1, 2 ORDER BY 1, 2